def main(alert):
    sent_emails = alert.get('related_messages', alert.get('sent_messages', []))
    recipients = []
    message_ids = []
    for email in sent_emails:
        msg_id = email.get('message_id', '')
        if msg_id:
            message_ids.append(msg_id)
        rcpts = email.get('recipients', email.get('to', []))
        if isinstance(rcpts, str):
            rcpts = [r.strip() for r in rcpts.split(',')]
        recipients.extend(rcpts)
    return {
        'compromised_user': alert.get('sender', ''),
        'message_ids': list(set(message_ids)),
        'affected_recipients': list(set(recipients)),
        'email_count': len(message_ids),
        'recipient_count': len(set(recipients))
    }

